import { isNullOrUndefinedOrEmpty } from '../validation/null-checks.js'

/**
 * Capitaliza solo la primera letra de un string
 * @param {string} string
 * @returns {string}
 */
export const primeraLetraMayusculas = (string) => {
  if (isNullOrUndefinedOrEmpty(string)) return ''
  return string.charAt(0).toUpperCase() + string.slice(1).toLowerCase()
}

/**
 * Elimina tildes y diacríticos
 * @param {string} string
 * @returns {string}
 */
export const removeTilde = (string) => {
  return string.normalize('NFD').replace(/[\u0300-\u036f]/g, '')
}

/**
 * Reemplaza caracteres especiales y acentos
 * @param {string} value
 * @returns {string}
 */
export const replaceSpecialChar = (value) => {
  return value
    .replace(/[áäâàã]/gi, 'a')
    .replace(/[éëêè]/gi, 'e')
    .replace(/[íïîì]/gi, 'i')
    .replace(/[óöôòõ]/gi, 'o')
    .replace(/[úüûù]/gi, 'u')
    .replace(/ñ/gi, 'n')
    .replace(/[^a-zA-Z\s]/gi, '')
}
